#include<bits/stdc++.h>
using namespace std;
const long long N=200010;
struct edge
{
    int u,v,w;
}e[N*4];
long long n,m,r,p;
vector<pair<long long,long long>> mp[N];
long long rnk[N],top[N],siz[N],son[N],d[N],fa[N],dfn[N],val[N],dfncnt;
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(auto i:mp[x])
    {
        long long v=i.first;
        if(v!=f)
        {
            d[v]=d[x]+1;
            fa[v]=x;
            val[v]=i.second;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            long long v=i.first;
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r,sum,max1,min1;
        long long lson,rson;
        long long add_tag,mul_tag;
        node():add_tag(0),mul_tag(1){}
    }a[N*3];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long ad=a[x].add_tag,mu=a[x].mul_tag;
        a[ls].sum=(a[ls].sum*mu+(mid-a[x].l+1)*ad);
        a[rs].sum=(a[rs].sum*mu+(a[x].r-mid)*ad);
        a[ls].max1=(a[ls].max1*mu+ad);
        a[rs].max1=(a[rs].max1*mu+ad);
        a[ls].min1=(a[ls].min1*mu+ad);
        a[rs].min1=(a[rs].min1*mu+ad);
        if(mu<0)
        {
            swap(a[ls].max1,a[ls].min1);
            swap(a[rs].max1,a[rs].min1);
        }
        a[ls].mul_tag=(a[ls].mul_tag*mu);
        a[rs].mul_tag=(a[rs].mul_tag*mu);
        a[ls].add_tag=(a[ls].add_tag*mu+ad);
        a[rs].add_tag=(a[rs].add_tag*mu+ad);
        a[x].add_tag=0;
        a[x].mul_tag=1;
    }
    long long init1(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=a[x].max1=a[x].min1=val[rnk[l]];
            return x;
        }
        a[x].lson=init1(l,mid);
        a[x].rson=init1(mid+1,r);
        pushup(x);
        return x;
    }
    void init(long long n)
    {
        init1(1,n);
    }
    void add1(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum+((a[x].r-a[x].l+1)*z));
            a[x].max1=(a[x].max1+z);
            a[x].min1=(a[x].min1+z);
            a[x].add_tag=(a[x].add_tag+z);
            return;
        }
        pushdown(x);
        add1(a[x].lson,l,r,z);
        add1(a[x].rson,l,r,z);
        pushup(x);
    }
    void add(long long l,long long r,long long x)
    {
        add1(1,l,r,x);
    }
    void mul1(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum*z);
            a[x].max1=(a[x].max1*z);
            a[x].min1=(a[x].min1*z);
            if(z<0)
            {
                swap(a[x].max1,a[x].min1);
            }
            a[x].add_tag=(a[x].add_tag*z);
            a[x].mul_tag=(a[x].mul_tag*z);
            return;
        }
        pushdown(x);
        mul1(a[x].lson,l,r,z);
        mul1(a[x].rson,l,r,z);
        pushup(x);
    }
    void mul(long long l,long long r,long long x)
    {
        mul1(1,l,r,x);
    }
    long long getsum1(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum1(a[x].lson,l,r)+getsum1(a[x].rson,l,r));
    }
    long long getsum(long long l,long long r)
    {
        return getsum1(1,l,r);
    }
    long long getmax1(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -1e15;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        pushdown(x);
        return max(getmax1(a[x].lson,l,r),getmax1(a[x].rson,l,r));
    }
    long long getmax(long long l,long long r)
    {
        return getmax1(1,l,r);
    }
    long long getmin1(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e15;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        pushdown(x);
        return min(getmin1(a[x].lson,l,r),getmin1(a[x].rson,l,r));
    }
    long long getmin(long long l,long long r)
    {
        return getmin1(1,l,r);
    }
    void xiangfan(long long l,long long r)
    {
        mul(l,r,-1);
    }
    void update(long long l,long long r,long long v)
    {
        mul(l,r,0);
        add(l,r,v);
    }
}t;
long long getsum(long long x,long long y)
{
    long long ans=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans+=t.getsum(dfn[top[x]],dfn[x]);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans+=t.getsum(dfn[x]+1,dfn[y]);
    return ans;
}
long long getmin(long long x,long long y)
{
    long long ans=LLONG_MAX;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans=min(ans,t.getmin(dfn[top[x]],dfn[x]));
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=min(ans,t.getmin(dfn[x]+1,dfn[y]));
    return ans;
}
long long getmax(long long x,long long y)
{
    long long ans=LLONG_MIN;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans=max(ans,t.getmax(dfn[top[x]],dfn[x]));
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=max(ans,t.getmax(dfn[x]+1,dfn[y]));
    return ans;
}
void xiangfan(long long x,long long y)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.xiangfan(dfn[top[x]],dfn[x]);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.xiangfan(dfn[x]+1,dfn[y]);
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        u++;
        v++;
        e[i]=(edge){u,v,w};
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs1(1);
    dfs2(1,1);
    t.init(n);
    long long q;
    scanf("%lld",&q);
    while(q--)
    {
        string s;
        long long x,y;
        cin>>s;
        scanf("%lld%lld",&x,&y);
        if(s!="C")
        {
            x++;
            y++;
        }
        if(s=="C")
        {
            long long u=e[x].u,v=e[x].v;
            if(d[u]>d[v])
            {
                swap(u,v);
            }
            t.update(dfn[v],dfn[v],y);
        }
        else if(s=="N")
        {
            xiangfan(x,y);
        }
        else if(s=="SUM")
        {
            printf("%lld\n",getsum(x,y));
        }
        else if(s=="MAX")
        {
            printf("%lld\n",getmax(x,y));
        }
        else
        {
            printf("%lld\n",getmin(x,y));
        }
    }
    return 0;
}
